const crypto = require('crypto');
const text = (input || '').trim();
if (!text) { print('Usage: !sha256 <text>'); }
else { print(crypto.createHash('sha256').update(text).digest('hex')); }

const arg = (input || '').trim();
let len = parseInt(arg, 10);
if (isNaN(len)) len = 16;
if (len < 4) len = 4;
if (len > 128) len = 128;
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*-_=+';
let pw = '';
for (let i = 0; i < len; i++) {
  pw += chars[Math.floor(Math.random() * chars.length)];
}
print('Your new ' + len + '-char password: ' + pw);

var choices=['rock','paper','scissors'];
var player=(input||'').trim().toLowerCase();
var emoji={rock:'\u270a',paper:'\u270b',scissors:'\u270c\ufe0f'};
if(choices.indexOf(player)===-1){print('Pick one: !rps rock | paper | scissors');return;}
var bot=choices[Math.floor(Math.random()*3)];
var beats={rock:'scissors',paper:'rock',scissors:'paper'};
var result;
if(player===bot){result='Tie!';}
else if(beats[player]===bot){result='You win!';}
else{result='I win!';}
print('You '+emoji[player]+' '+player+' vs me '+emoji[bot]+' '+bot+' \u2014 '+result);

